use crate::errors::MultivariousError;
use crate::common_types::{Matrix, Vector};
use crate::projector::{
    traits::{Project, Reconstruct, PartialProject, ProjectorConfig},
    BaseProjector, BaseProjectorBuilder,
};
use crate::preprocessing::{Preprocessor, Center, Scale, Standardize, PreprocessPipeline};
use crate::svd::{SvdMethod, SvdConfig, svd_factory};
use crate::validation::{check_dimensions_match, check_is_fitted, check_non_negative};
use ndarray::{Array1, Array2, Axis};
use serde::{Serialize, Deserialize};
use std::fmt;

/// Principal Component Analysis (PCA)
/// 
/// PCA is a statistical procedure that uses an orthogonal transformation to convert
/// a set of observations of possibly correlated variables into a set of values of
/// linearly uncorrelated variables called principal components.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Pca {
    /// Base projector containing the projection matrix
    base_projector: BaseProjector,

    /// Singular values from SVD
    singular_values: Vector,

    /// Standard deviations of components
    standard_deviations: Vector,

    /// Explained variance ratio for each component
    explained_variance_ratio: Vector,

    /// Cumulative explained variance ratio
    cumulative_variance_ratio: Vector,

    /// Total variance in the original data
    total_variance: f64,

    /// Number of samples used for fitting
    n_samples: usize,

    /// Preprocessing pipeline
    preprocessor: Option<PreprocessPipeline>,

    /// SVD method used
    svd_method: SvdMethod,

    /// Configuration
    config: PcaConfig,
}

/// Configuration for PCA
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PcaConfig {
    /// Base projector configuration
    pub projector_config: ProjectorConfig,

    /// SVD method to use
    pub svd_method: SvdMethod,

    /// SVD configuration
    pub svd_config: SvdConfig,

    /// Whether to use correlation matrix (standardize) or covariance matrix (center only)
    pub use_correlation: bool,

    /// Minimum variance to retain (between 0 and 1)
    pub min_variance_retained: Option<f64>,

    /// Whether to compute all components or just the requested number
    pub compute_all_components: bool,
}

impl Default for PcaConfig {
    fn default() -> Self {
        Self {
            projector_config: ProjectorConfig::default(),
            svd_method: SvdMethod::Auto,
            svd_config: SvdConfig::default(),
            use_correlation: false,
            min_variance_retained: None,
            compute_all_components: false,
        }
    }
}

impl Pca {
    /// Create a new unfitted PCA instance
    pub fn new(config: PcaConfig) -> Self {
        let n_features = 0;
        let n_components = config.projector_config.n_components.unwrap_or(0);

        Self {
            base_projector: BaseProjector::new_unfitted(n_features, n_components, config.projector_config.clone()),
            singular_values: Vector::zeros(0),
            standard_deviations: Vector::zeros(0),
            explained_variance_ratio: Vector::zeros(0),
            cumulative_variance_ratio: Vector::zeros(0),
            total_variance: 0.0,
            n_samples: 0,
            preprocessor: None,
            svd_method: config.svd_method,
            config,
        }
    }

    /// Fit the PCA model to data
    pub fn fit(&mut self, data: &Matrix) -> Result<(), MultivariousError> {
        let (n_samples, n_features) = data.dim();

        if n_samples < 2 {
            return Err(MultivariousError::InvalidParameter {
                name: "n_samples".to_string(),
                value: n_samples.to_string(),
                reason: "PCA requires at least 2 samples".to_string(),
            });
        }

        if n_features < 1 {
            return Err(MultivariousError::InvalidParameter {
                name: "n_features".to_string(),
                value: n_features.to_string(),
                reason: "PCA requires at least 1 feature".to_string(),
            });
        }

        self.n_samples = n_samples;

        // Set up preprocessing
        let mut pipeline = PreprocessPipeline::new();

        if self.config.use_correlation {
            // Standardize (mean=0, std=1)
            pipeline = pipeline.add_step(Box::new(Standardize::new(Axis(0))));
        } else {
            // Just center (mean=0)
            pipeline = pipeline.add_step(Box::new(Center::new(Axis(0))));
        }

        // Fit and transform the data
        let preprocessed = pipeline.fit_transform(data)?;
        self.preprocessor = Some(pipeline);

        // Determine number of components
        let max_components = n_features.min(n_samples - 1);
        let n_components = if let Some(n) = self.config.projector_config.n_components {
            n.min(max_components)
        } else if let Some(min_var) = self.config.min_variance_retained {
            // Will determine after SVD
            max_components
        } else {
            max_components
        };

        // Configure SVD
        let mut svd_config = self.config.svd_config.clone();
        svd_config.n_components = Some(n_components);

        // Select SVD method
        let svd_method = if self.config.svd_method == SvdMethod::Auto {
            // Auto-select based on matrix size
            if n_samples * n_features < 1000 {
                SvdMethod::Full
            } else if n_components < max_components / 2 {
                SvdMethod::Truncated
            } else {
                SvdMethod::Full
            }
        } else {
            self.config.svd_method
        };

        // Create SVD solver
        let solver = svd_factory(svd_method, svd_config)?;

        // Compute SVD
        let svd_result = solver.compute(&preprocessed)?;

        // Store singular values and compute variance explained
        self.singular_values = svd_result.singular_values.clone();

        // Standard deviations are singular values scaled by sqrt(n-1)
        let scale_factor = (n_samples - 1) as f64;
        self.standard_deviations = &self.singular_values / scale_factor.sqrt();

        // Compute explained variance ratio
        let variances = self.standard_deviations.mapv(|x| x * x);
        self.total_variance = variances.sum();

        if self.total_variance > 0.0 {
            self.explained_variance_ratio = &variances / self.total_variance;
        } else {
            self.explained_variance_ratio = Vector::zeros(variances.len());
        }

        // Compute cumulative variance ratio
        self.cumulative_variance_ratio = Vector::zeros(self.explained_variance_ratio.len());
        let mut cumsum = 0.0;
        for (i, &ratio) in self.explained_variance_ratio.iter().enumerate() {
            cumsum += ratio;
            self.cumulative_variance_ratio[i] = cumsum;
        }

        // Determine final number of components if using min_variance_retained
        let final_n_components = if let Some(min_var) = self.config.min_variance_retained {
            // Find the number of components that explain at least min_var of variance
            let n = self.cumulative_variance_ratio
                .iter()
                .position(|&x| x >= min_var)
                .map(|i| i + 1)
                .unwrap_or(n_components);
            n.min(n_components)
        } else {
            n_components
        };

        // Extract the components (V^T from SVD)
        let components = if let Some(vt) = svd_result.vt {
            vt.slice(ndarray::s![..final_n_components, ..]).to_owned()
        } else {
            return Err(MultivariousError::ComputationError(
                "SVD did not return V^T matrix".to_string()
            ));
        };

        // Create projection matrix (transpose of components for our convention)
        let projection_matrix = components.t().to_owned();

        // Update base projector
        self.base_projector = BaseProjector::new(projection_matrix, self.config.projector_config.clone())?;

        // Truncate variance arrays if needed
        if final_n_components < self.singular_values.len() {
            self.singular_values = self.singular_values.slice(ndarray::s![..final_n_components]).to_owned();
            self.standard_deviations = self.standard_deviations.slice(ndarray::s![..final_n_components]).to_owned();
            self.explained_variance_ratio = self.explained_variance_ratio.slice(ndarray::s![..final_n_components]).to_owned();
            self.cumulative_variance_ratio = self.cumulative_variance_ratio.slice(ndarray::s![..final_n_components]).to_owned();
        }

        self.svd_method = svd_method;

        Ok(())
    }

    /// Fit the model and transform the data in one step
    pub fn fit_transform(&mut self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        self.fit(data)?;
        self.transform(data)
    }

    /// Transform data using the fitted PCA model
    pub fn transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Apply preprocessing
        let preprocessed = if let Some(ref preprocessor) = self.preprocessor {
            preprocessor.transform(data)?
        } else {
            data.clone()
        };

        // Use base projector for transformation
        self.base_projector.project(&preprocessed)
    }

    /// Inverse transform data from component space back to original space
    pub fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Use base projector for inverse transformation
        let reconstructed = self.base_projector.reconstruct(data)?;

        // Apply inverse preprocessing
        if let Some(ref preprocessor) = self.preprocessor {
            preprocessor.inverse_transform(&reconstructed)
        } else {
            Ok(reconstructed)
        }
    }

    /// Get the principal components (loadings)
    pub fn components(&self) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Return transpose of projection matrix to match sklearn convention
        Ok(self.base_projector.projection_matrix().t().to_owned())
    }

    /// Get singular values
    pub fn singular_values(&self) -> &Vector {
        &self.singular_values
    }

    /// Get explained variance ratio
    pub fn explained_variance_ratio(&self) -> &Vector {
        &self.explained_variance_ratio
    }

    /// Get cumulative explained variance ratio
    pub fn cumulative_variance_ratio(&self) -> &Vector {
        &self.cumulative_variance_ratio
    }

    /// Get total variance explained by selected components
    pub fn total_variance_explained(&self) -> f64 {
        self.explained_variance_ratio.sum()
    }
}

// Implement projection traits
impl Project for Pca {
    fn project(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        self.transform(data)
    }

    fn n_components(&self) -> usize {
        self.base_projector.n_components()
    }

    fn n_features(&self) -> usize {
        self.base_projector.n_features()
    }

    fn is_fitted(&self) -> bool {
        self.base_projector.is_fitted()
    }

    fn name(&self) -> &str {
        "PCA"
    }
}

impl Reconstruct for Pca {
    fn reconstruct(&self, projected: &Matrix) -> Result<Matrix, MultivariousError> {
        self.inverse_transform(projected)
    }
}

impl PartialProject for Pca {
    fn project_components(&self, data: &Matrix, component_indices: &[usize]) -> Result<Matrix, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        // Apply preprocessing
        let preprocessed = if let Some(ref preprocessor) = self.preprocessor {
            preprocessor.transform(data)?
        } else {
            data.clone()
        };

        // Use base projector for partial projection
        self.base_projector.project_components(&preprocessed, component_indices)
    }

    fn component_importance(&self) -> Result<Vector, MultivariousError> {
        if !self.is_fitted() {
            return Err(MultivariousError::NotFitted("PCA".to_string()));
        }

        Ok(self.explained_variance_ratio.clone())
    }
}

impl fmt::Display for Pca {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        if self.is_fitted() {
            write!(
                f,
                "PCA(n_components={}, n_features={}, method={:?}, variance_explained={:.2}%)",
                self.n_components(),
                self.n_features(),
                self.svd_method,
                self.total_variance_explained() * 100.0
            )
        } else {
            write!(f, "PCA(unfitted)")
        }
    }
}

/// Builder for PCA
#[derive(Debug, Clone)]
pub struct PcaBuilder {
    config: PcaConfig,
}

impl PcaBuilder {
    pub fn new() -> Self {
        Self {
            config: PcaConfig::default(),
        }
    }

    /// Set the number of components
    pub fn n_components(mut self, n: usize) -> Self {
        self.config.projector_config.n_components = Some(n);
        self
    }

    /// Set minimum variance to retain
    pub fn min_variance(mut self, ratio: f64) -> Self {
        self.config.min_variance_retained = Some(ratio);
        self
    }

    /// Use correlation matrix instead of covariance
    pub fn use_correlation(mut self, use_corr: bool) -> Self {
        self.config.use_correlation = use_corr;
        self
    }

    /// Set SVD method
    pub fn svd_method(mut self, method: SvdMethod) -> Self {
        self.config.svd_method = method;
        self
    }

    /// Set whether to center data
    pub fn center(mut self, center: bool) -> Self {
        self.config.projector_config.center = center;
        self
    }

    /// Set whether to scale data
    pub fn scale(mut self, scale: bool) -> Self {
        self.config.projector_config.scale = scale;
        self
    }

    /// Set random state for reproducibility
    pub fn random_state(mut self, seed: u64) -> Self {
        self.config.projector_config.random_state = Some(seed);
        self.config.svd_config.random_state = Some(seed);
        self
    }

    /// Build the PCA instance
    pub fn build(self) -> Pca {
        Pca::new(self.config)
    }
}

impl Default for PcaBuilder {
    fn default() -> Self {
        Self::new()
    }
}

