/// Check if dimensions match, returning error if not
pub fn check_dimensions_match(
    actual: usize,
    expected: usize,
    actual_name: &str,
    expected_name: &str,
) -> Result<(), MultivariousError> {
    if actual != expected {
        Err(MultivariousError::DimensionMismatch {
            expected: format!("{} ({})", expected, expected_name),
            actual: format!("{} ({})", actual, actual_name),
        })
    } else {
        Ok(())
    }
}

/// Check if a model has been fitted
pub fn check_is_fitted(fitted: bool, model_name: &str) -> Result<(), MultivariousError> {
    if !fitted {
        Err(MultivariousError::ValidationError {
            message: format!("{} has not been fitted yet. Call fit() before using transform().", model_name),
        })
    } else {
        Ok(())
    }
}

/// Check if value is non-negative
pub fn check_non_negative(value: f64, name: &str) -> Result<(), MultivariousError> {
    if value < 0.0 {
        Err(MultivariousError::InvalidParameter {
            name: name.to_string(),
            value: value.to_string(),
            reason: "must be non-negative".to_string(),
        })
    } else {
        Ok(())
    }
}

