use crate::errors::{MultivariousError, Result};
use crate::common_types::{Shape, Matrix};
use ndarray::{Array2, Array1, ArrayBase, Data, Ix2};

/// Validate that two matrices have compatible dimensions for multiplication
/// Returns Ok if A.ncols == B.nrows
pub fn validate_matrix_multiply(a_shape: Shape, b_shape: Shape) -> Result<()> {
    if a_shape.1 != b_shape.0 {
        return Err(MultivariousError::DimensionMismatch {
            expected: format!("A: {:?}, B: ({}, _)", a_shape, a_shape.1),
            actual: format!("A: {:?}, B: {:?}", a_shape, b_shape),
        });
    }
    Ok(())
}

/// Validate that two arrays have the same shape
pub fn validate_same_shape(a_shape: &[usize], b_shape: &[usize]) -> Result<()> {
    if a_shape != b_shape {
        return Err(MultivariousError::DimensionMismatch {
            expected: format!("{:?}", a_shape),
            actual: format!("{:?}", b_shape),
        });
    }
    Ok(())
}

/// Validate that a matrix is square
pub fn validate_square_matrix(shape: Shape) -> Result<()> {
    if shape.0 != shape.1 {
        return Err(MultivariousError::ValidationError(
            format!("Matrix must be square, got shape {:?}", shape)
        ));
    }
    Ok(())
}

/// Validate that the number of components is valid
pub fn validate_n_components(n_components: usize, max_components: usize) -> Result<()> {
    if n_components == 0 {
        return Err(MultivariousError::InvalidParameter {
            name: "n_components".to_string(),
            value: n_components.to_string(),
            reason: "must be at least 1".to_string(),
        });
    }

    if n_components > max_components {
        return Err(MultivariousError::InvalidParameter {
            name: "n_components".to_string(),
            value: n_components.to_string(),
            reason: format!("cannot exceed {}", max_components),
        });
    }

    Ok(())
}

/// Validate that a tolerance value is positive
pub fn validate_tolerance(tol: f64, param_name: &str) -> Result<()> {
    if tol <= 0.0 {
        return Err(MultivariousError::InvalidParameter {
            name: param_name.to_string(),
            value: tol.to_string(),
            reason: "must be positive".to_string(),
        });
    }
    Ok(())
}

/// Validate that an iteration count is positive
pub fn validate_max_iter(max_iter: usize) -> Result<()> {
    if max_iter == 0 {
        return Err(MultivariousError::InvalidParameter {
            name: "max_iter".to_string(),
            value: max_iter.to_string(),
            reason: "must be at least 1".to_string(),
        });
    }
    Ok(())
}

/// Check if a matrix contains any NaN or infinite values
pub fn validate_finite(data: &Array2<f64>) -> Result<()> {
    if !data.iter().all(|x| x.is_finite()) {
        return Err(MultivariousError::ValidationError(
            "Data contains NaN or infinite values".to_string()
        ));
    }
    Ok(())
}

/// Check if a vector contains any NaN or infinite values
pub fn validate_finite_vec(data: &Array1<f64>) -> Result<()> {
    if !data.iter().all(|x| x.is_finite()) {
        return Err(MultivariousError::ValidationError(
            "Vector contains NaN or infinite values".to_string()
        ));
    }
    Ok(())
}

/// Validate that data matrix has at least min_samples rows
pub fn validate_min_samples(n_samples: usize, min_samples: usize) -> Result<()> {
    if n_samples < min_samples {
        return Err(MultivariousError::ValidationError(
            format!("Need at least {} samples, got {}", min_samples, n_samples)
        ));
    }
    Ok(())
}

/// Validate that indices are within bounds
pub fn validate_indices(indices: &[usize], max_index: usize) -> Result<()> {
    for &idx in indices {
        if idx >= max_index {
            return Err(MultivariousError::ValidationError(
                format!("Index {} is out of bounds (max: {})", idx, max_index - 1)
            ));
        }
    }
    Ok(())
}

/// Validate that a matrix is not empty
pub fn validate_matrix_not_empty<S>(matrix: &ArrayBase<S, Ix2>, name: &str) -> Result<()>
where
    S: Data<Elem = f64>,
{
    let shape = matrix.shape();
    if shape[0] == 0 || shape[1] == 0 {
        return Err(MultivariousError::ValidationError(
            format!("{} matrix cannot be empty (shape: {:?})", name, shape)
        ));
    }
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use ndarray::array;

    #[test]
    fn test_validate_matrix_multiply() {
        // Valid multiplication
        assert!(validate_matrix_multiply((3, 4), (4, 5)).is_ok());

        // Invalid multiplication
        assert!(validate_matrix_multiply((3, 4), (5, 6)).is_err());
    }

    #[test]
    fn test_validate_same_shape() {
        assert!(validate_same_shape(&[3, 4], &[3, 4]).is_ok());
        assert!(validate_same_shape(&[3, 4], &[4, 3]).is_err());
    }

    #[test]
    fn test_validate_square_matrix() {
        assert!(validate_square_matrix((4, 4)).is_ok());
        assert!(validate_square_matrix((3, 4)).is_err());
    }

    #[test]
    fn test_validate_n_components() {
        assert!(validate_n_components(3, 10).is_ok());
        assert!(validate_n_components(0, 10).is_err());
        assert!(validate_n_components(11, 10).is_err());
    }

    #[test]
    fn test_validate_tolerance() {
        assert!(validate_tolerance(1e-6, "tol").is_ok());
        assert!(validate_tolerance(0.0, "tol").is_err());
        assert!(validate_tolerance(-1e-6, "tol").is_err());
    }

    #[test]
    fn test_validate_finite() {
        let good_data = array![[1.0, 2.0], [3.0, 4.0]];
        assert!(validate_finite(&good_data).is_ok());

        let bad_data = array![[1.0, f64::NAN], [3.0, 4.0]];
        assert!(validate_finite(&bad_data).is_err());

        let inf_data = array![[1.0, 2.0], [f64::INFINITY, 4.0]];
        assert!(validate_finite(&inf_data).is_err());
    }

    #[test]
    fn test_validate_indices() {
        assert!(validate_indices(&[0, 1, 2], 5).is_ok());
        assert!(validate_indices(&[0, 5, 2], 5).is_err());
    }
}

