use thiserror::Error;

/// The main error type for the multivarious library
#[derive(Error, Debug)]
pub enum MultivariousError {
    /// Dimension mismatch between matrices or vectors
    #[error("Dimension mismatch: expected {expected}, got {actual}")]
    DimensionMismatch { expected: String, actual: String },

    /// Linear algebra operation error
    #[error("Linear algebra error: {0}")]
    LinAlgError(String),

    /// Invalid number of components requested
    #[error("Invalid component count: {0}")]
    InvalidComponentCount(usize),

    /// Singular matrix encountered
    #[error("Singular matrix: {0}")]
    SingularMatrix(String),

    /// Convergence failure in iterative algorithm
    #[error("Convergence error: {0}")]
    ConvergenceError(String),

    /// Invalid parameter value
    #[error("Invalid parameter: {name} = {value}, {reason}")]
    InvalidParameter {
        name: String,
        value: String,
        reason: String,
    },

    /// Data validation error
    #[error("Data validation error: {0}")]
    ValidationError(String),

    /// Preprocessing error
    #[error("Preprocessing error: {0}")]
    PreprocessingError(String),

    /// IO error wrapper
    #[error("IO error: {0}")]
    IoError(#[from] std::io::Error),

    /// Serialization error
    #[error("Serialization error: {0}")]
    SerializationError(String),

    /// Feature not implemented
    #[error("Feature not implemented: {0}")]
    NotImplemented(String),

    /// Generic error for other cases
    #[error("{0}")]
    Other(String),
}

/// Specialized result type for the multivarious library
pub type Result<T> = std::result::Result<T, MultivariousError>;

// Implement conversion from ndarray-linalg errors when that crate is added
// impl From<ndarray_linalg::error::LinalgError> for MultivariousError {
//     fn from(err: ndarray_linalg::error::LinalgError) -> Self {
//         MultivariousError::LinAlgError(err.to_string())
//     }
// }

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_dimension_mismatch_error() {
        let err = MultivariousError::DimensionMismatch {
            expected: "(10, 5)".to_string(),
            actual: "(10, 3)".to_string(),
        };
        assert_eq!(
            err.to_string(),
            "Dimension mismatch: expected (10, 5), got (10, 3)"
        );
    }

    #[test]
    fn test_invalid_parameter_error() {
        let err = MultivariousError::InvalidParameter {
            name: "n_components".to_string(),
            value: "0".to_string(),
            reason: "must be at least 1".to_string(),
        };
        assert_eq!(
            err.to_string(),
            "Invalid parameter: n_components = 0, must be at least 1"
        );
    }
}

