    16→use crate::errors::MultivariousError;
    17→use serde::{Deserialize, Serialize};
    18→use std::fmt;
    19→
    20→/// Method for computing SVD
    21→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
    22→pub enum SvdMethod {
    23→    /// Standard full SVD decomposition
    24→    Full,
    25→    /// Thin SVD (economy size decomposition)
    26→    Thin,
    27→    /// Truncated SVD with specified number of components
    28→    Truncated(usize),
    29→    /// Randomized SVD for large matrices
    30→    Randomized {
    31→        /// Number of components to compute
    32→        n_components: usize,
    33→        /// Number of power iterations for accuracy
    34→        n_iter: usize,
    35→        /// Random seed for reproducibility
    36→        seed: Option<u64>,
    37→    },
    38→}
    39→
    40→impl fmt::Display for SvdMethod {
    41→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
    42→        match self {
    43→            SvdMethod::Full => write!(f, "Full SVD"),
    44→            SvdMethod::Thin => write!(f, "Thin SVD"),
    45→            SvdMethod::Truncated(k) => write!(f, "Truncated SVD (k={})", k),
    46→            SvdMethod::Randomized { n_components, n_iter, .. } => {
    47→                write!(f, "Randomized SVD (k={}, iter={})", n_components, n_iter)
    48→            }
    49→        }
    50→    }
    51→}
    52→
    53→/// Result of SVD decomposition
    54→#[derive(Debug, Clone)]
    55→pub struct SvdResult {
    56→    /// Left singular vectors (U matrix)
    57→    pub u: Matrix,
    58→    /// Singular values (diagonal of S)
    59→    pub s: Vector,
    60→    /// Right singular vectors (V^T matrix)
    61→    pub vt: Matrix,
    62→    /// Method used for decomposition
    63→    pub method: SvdMethod,
    64→    /// Number of iterations (for iterative methods)
    65→    pub n_iter: Option<usize>,
    66→    /// Explained variance ratio for each component
    67→    pub explained_variance_ratio: Option<Vector>,
    68→}
