//! Singular Value Decomposition (SVD) module

mod standard;
mod truncated;
mod randomized;
mod factory;

// Re-export all SVD types
pub use self::standard::*;
pub use self::truncated::*;
pub use self::randomized::*;
pub use self::factory::*;

// Re-export types from parent module
use crate::common_types::{Matrix, Vector};
use crate::errors::MultivariousError;
use serde::{Deserialize, Serialize};
use std::fmt;

/// Method for computing SVD
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum SvdMethod {
    /// Standard full SVD decomposition
    Full,
    /// Thin SVD (economy size decomposition)
    Thin,
    /// Truncated SVD with specified number of components
    Truncated(usize),
    /// Randomized SVD for large matrices
    Randomized {
        /// Number of components to compute
        n_components: usize,
        /// Number of power iterations for accuracy
        n_iter: usize,
        /// Random seed for reproducibility
        seed: Option<u64>,
    },
}

impl fmt::Display for SvdMethod {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            SvdMethod::Full => write!(f, "Full SVD"),
            SvdMethod::Thin => write!(f, "Thin SVD"),
            SvdMethod::Truncated(k) => write!(f, "Truncated SVD (k={})", k),
            SvdMethod::Randomized { n_components, n_iter, .. } => {
                write!(f, "Randomized SVD (k={}, iter={})", n_components, n_iter)
            }
        }
    }
}

/// Result of SVD decomposition
#[derive(Debug, Clone)]
pub struct SvdResult {
    /// Left singular vectors (U matrix)
    pub u: Matrix,
    /// Singular values (diagonal of S)
    pub s: Vector,
    /// Right singular vectors (V^T matrix)
    pub vt: Matrix,
    /// Method used for decomposition
    pub method: SvdMethod,
    /// Number of iterations (for iterative methods)
    pub n_iter: Option<usize>,
    /// Explained variance ratio for each component
    pub explained_variance_ratio: Option<Vector>,
}

impl SvdResult {
    /// Reconstruct the original matrix from SVD components
    pub fn reconstruct(&self) -> Matrix {
        let s_diag = Matrix::from_diag(&self.s);
        self.u.dot(&s_diag).dot(&self.vt)
    }

    /// Get the number of components
    pub fn n_components(&self) -> usize {
        self.s.len()
    }

    /// Get the total variance explained
    pub fn total_variance_explained(&self) -> Option<f64> {
        self.explained_variance_ratio.as_ref().map(|evr| evr.sum())
    }

    /// Get cumulative explained variance ratio
    pub fn cumulative_variance_ratio(&self) -> Option<Vector> {
        self.explained_variance_ratio.as_ref().map(|evr| {
            let mut cumsum = Vector::zeros(evr.len());
            let mut sum = 0.0;
            for (i, &val) in evr.iter().enumerate() {
                sum += val;
                cumsum[i] = sum;
            }
            cumsum
        })
    }
}

/// Trait for SVD solvers
pub trait SvdSolver {
    /// Compute SVD decomposition
    fn compute(&self, matrix: &Matrix, method: SvdMethod) -> Result<SvdResult, MultivariousError>;

    /// Compute only singular values (faster than full SVD)
    fn singular_values(&self, matrix: &Matrix) -> Result<Vector, MultivariousError>;

    /// Estimate the rank of a matrix using SVD
    fn matrix_rank(&self, matrix: &Matrix, tol: Option<f64>) -> Result<usize, MultivariousError>;
}

/// Configuration for SVD computation
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SvdConfig {
    /// Method to use
    pub method: SvdMethod,
    /// Whether to compute U matrix
    pub compute_u: bool,
    /// Whether to compute V^T matrix
    pub compute_vt: bool,
    /// Tolerance for numerical operations
    pub tolerance: f64,
    /// Maximum iterations for iterative methods
    pub max_iter: usize,
    /// Whether to center the data before SVD
    pub center: bool,
}

impl Default for SvdConfig {
    fn default() -> Self {
        Self {
            method: SvdMethod::Full,
            compute_u: true,
            compute_vt: true,
            tolerance: 1e-10,
            max_iter: 1000,
            center: false,
        }
    }
}

impl SvdConfig {
    /// Create a config for thin SVD
    pub fn thin() -> Self {
        Self {
            method: SvdMethod::Thin,
            ..Default::default()
        }
    }

    /// Create a config for truncated SVD
    pub fn truncated(n_components: usize) -> Self {
        Self {
            method: SvdMethod::Truncated(n_components),
            ..Default::default()
        }
    }

    /// Create a config for randomized SVD
    pub fn randomized(n_components: usize) -> Self {
        Self {
            method: SvdMethod::Randomized {
                n_components,
                n_iter: 4,
                seed: None,
            },
            ..Default::default()
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_svd_method_display() {
        assert_eq!(SvdMethod::Full.to_string(), "Full SVD");
        assert_eq!(SvdMethod::Thin.to_string(), "Thin SVD");
        assert_eq!(SvdMethod::Truncated(10).to_string(), "Truncated SVD (k=10)");
        assert_eq!(
            SvdMethod::Randomized {
                n_components: 5,
                n_iter: 3,
                seed: None
            }
            .to_string(),
            "Randomized SVD (k=5, iter=3)"
        );
    }

    #[test]
    fn test_svd_config_default() {
        let config = SvdConfig::default();
        assert_eq!(config.method, SvdMethod::Full);
        assert!(config.compute_u);
        assert!(config.compute_vt);
        assert_eq!(config.tolerance, 1e-10);
        assert_eq!(config.max_iter, 1000);
        assert!(!config.center);
    }

    #[test]
    fn test_svd_config_presets() {
        let thin = SvdConfig::thin();
        assert_eq!(thin.method, SvdMethod::Thin);

        let truncated = SvdConfig::truncated(20);
        assert_eq!(truncated.method, SvdMethod::Truncated(20));

        let randomized = SvdConfig::randomized(15);
        match randomized.method {
            SvdMethod::Randomized { n_components, n_iter, seed } => {
                assert_eq!(n_components, 15);
                assert_eq!(n_iter, 4);
                assert_eq!(seed, None);
            }
            _ => panic!("Expected randomized SVD method"),
        }
    }
}

