/// Base projector implementation
/// 
/// This struct provides the fundamental projection operations used by
/// various dimensionality reduction techniques. It stores a projection
/// matrix and provides efficient forward and inverse transformations.
#[derive(Debug, Clone)]
pub struct BaseProjector {
    /// The projection matrix (n_features x n_components)
    /// Each column represents a component/direction in the original space
    projection_matrix: Matrix,

    /// Optional preprocessing mean for centering
    mean: Option<Vector>,

    /// Optional preprocessing scale for standardization
    scale: Option<Vector>,

    /// Configuration options
    config: ProjectorConfig,

    /// Cache for inverse projection matrices
    /// Key is the hash of component indices
    inverse_cache: Arc<RwLock<HashMap<u64, Matrix>>>,

    /// Whether the projector has been fitted
    fitted: bool,

    /// Name of the projector
    name: String,
}

impl BaseProjector {
    /// Create a new BaseProjector
    pub fn new(projection_matrix: Matrix, config: ProjectorConfig) -> Result<Self, MultivariousError> {
        if projection_matrix.is_empty() {
            return Err(MultivariousError::InvalidParameter {
                name: "projection_matrix".to_string(),
                value: "empty matrix".to_string(),
                reason: "projection matrix must have at least one component".to_string(),
            });
        }

        Ok(Self {
            projection_matrix,
            mean: None,
            scale: None,
            config,
            inverse_cache: Arc::new(RwLock::new(HashMap::new())),
            fitted: true,
            name: "BaseProjector".to_string(),
        })
    }

    /// Create a new unfitted BaseProjector
    pub fn new_unfitted(n_features: usize, n_components: usize, config: ProjectorConfig) -> Self {
        Self {
            projection_matrix: Matrix::zeros((n_features, n_components)),
            mean: None,
            scale: None,
            config,
            inverse_cache: Arc::new(RwLock::new(HashMap::new())),
            fitted: false,
            name: "BaseProjector".to_string(),
        }
    }

    /// Set the projection matrix and mark as fitted
    pub fn set_projection_matrix(&mut self, matrix: Matrix) -> Result<(), MultivariousError> {
        if matrix.is_empty() {
            return Err(MultivariousError::InvalidParameter {
                name: "projection_matrix".to_string(),
                value: "empty matrix".to_string(),
                reason: "projection matrix must have at least one component".to_string(),
            });
        }

        self.projection_matrix = matrix;
        self.fitted = true;
        // Clear the cache when projection matrix changes
        self.inverse_cache.write().unwrap().clear();
        Ok(())
    }

    /// Set preprocessing parameters
    pub fn set_preprocessing(&mut self, mean: Option<Vector>, scale: Option<Vector>) -> Result<(), MultivariousError> {
        // Validate dimensions if provided
        let n_features = self.projection_matrix.nrows();

        if let Some(ref m) = mean {
            if m.len() != n_features {
                return Err(MultivariousError::DimensionMismatch {
                    expected: n_features.to_string(),
                    actual: m.len().to_string(),
                });
            }
        }

        if let Some(ref s) = scale {
            if s.len() != n_features {
                return Err(MultivariousError::DimensionMismatch {
                    expected: n_features.to_string(),
                    actual: s.len().to_string(),
                });
            }
            // Check for zero or near-zero scale values
            if s.iter().any(|&val| val.abs() < 1e-10) {
                return Err(MultivariousError::InvalidParameter {
                    name: "scale".to_string(),
                    value: "contains zero or near-zero values".to_string(),
                    reason: "scale values must be non-zero for division".to_string(),
                });
            }
        }

        self.mean = mean;
        self.scale = scale;
        Ok(())
    }

    /// Get the projection matrix
    pub fn projection_matrix(&self) -> &Matrix {
        &self.projection_matrix
    }

    /// Apply preprocessing to data
    fn preprocess(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let mut result = data.clone();

        // Center the data
        if let Some(ref mean) = self.mean {
            for mut row in result.rows_mut() {
                row -= mean;
            }
        }

        // Scale the data
        if let Some(ref scale) = self.scale {
            for mut row in result.rows_mut() {
                row /= scale;
            }
        }

        Ok(result)
    }

    /// Apply inverse preprocessing to data
    fn inverse_preprocess(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let mut result = data.clone();

        // Unscale the data
        if let Some(ref scale) = self.scale {
            for mut row in result.rows_mut() {
                row *= scale;
            }
        }

        // Uncenter the data
        if let Some(ref mean) = self.mean {
            for mut row in result.rows_mut() {
                row += mean;
            }
        }

        Ok(result)
    }

    /// Compute hash for component indices (for caching)
    fn compute_indices_hash(indices: &[usize]) -> u64 {
        use std::collections::hash_map::DefaultHasher;
        use std::hash::{Hash, Hasher};

        let mut hasher = DefaultHasher::new();
        indices.hash(&mut hasher);
        hasher.finish()
    }

    /// Compute the pseudo-inverse for a subset of components
    fn compute_partial_inverse(&self, component_indices: &[usize]) -> Result<Matrix, MultivariousError> {
        // Extract the subset of the projection matrix
        let n_features = self.projection_matrix.nrows();
        let n_selected = component_indices.len();

        if n_selected == 0 {
            return Err(MultivariousError::InvalidParameter {
                name: "component_indices".to_string(),
                value: "empty".to_string(),
                reason: "at least one component must be selected".to_string(),
            });
        }

        // Create submatrix with selected components
        let mut submatrix = Matrix::zeros((n_features, n_selected));
        for (out_idx, &comp_idx) in component_indices.iter().enumerate() {
            if comp_idx >= self.projection_matrix.ncols() {
                return Err(MultivariousError::InvalidParameter {
                    name: "component_index".to_string(),
                    value: comp_idx.to_string(),
                    reason: format!("out of bounds (max: {})", self.projection_matrix.ncols() - 1),
                });
            }
            submatrix.column_mut(out_idx).assign(&self.projection_matrix.column(comp_idx));
        }

        // Compute pseudo-inverse using SVD or other method
        // For now, we'll use the transpose for orthogonal projections
        // In a full implementation, this would use proper pseudo-inverse computation
        Ok(submatrix.t().to_owned())
    }
}

