use crate::errors::MultivariousError;
use crate::common_types::{Matrix, Vector};
use crate::projector::traits::{Project, Reconstruct, PartialProject, ProjectorConfig};
use crate::validation::{check_dimensions_match, check_is_fitted};
use ndarray::{Array1, Array2, Axis};
use std::collections::HashMap;
use std::sync::{Arc, RwLock};
use serde::{Serialize, Deserialize};

/// Base projector implementation
/// 
/// This struct provides the fundamental projection operations used by
/// various dimensionality reduction techniques. It stores a projection
/// matrix and provides efficient forward and inverse transformations.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BaseProjector {
    /// The projection matrix (n_features x n_components)
    /// Each column represents a component/direction in the original space
    projection_matrix: Matrix,

    /// Optional preprocessing mean for centering
    mean: Option<Vector>,

    /// Optional preprocessing scale for standardization
    scale: Option<Vector>,

    /// Configuration options
    config: ProjectorConfig,

    /// Cache for inverse projection matrices
    /// Key is the hash of component indices
    inverse_cache: Arc<RwLock<HashMap<u64, Matrix>>>,

    /// Whether the projector has been fitted
    fitted: bool,

    /// Name of the projector
    name: String,
}

impl BaseProjector {
    /// Create a new BaseProjector
    pub fn new(projection_matrix: Matrix, config: ProjectorConfig) -> Result<Self, MultivariousError> {
        if projection_matrix.is_empty() {
            return Err(MultivariousError::InvalidParameter {
                name: "projection_matrix".to_string(),
                value: "empty matrix".to_string(),
                reason: "projection matrix must have at least one component".to_string(),
            });
        }

        Ok(Self {
            projection_matrix,
            mean: None,
            scale: None,
            config,
            inverse_cache: Arc::new(RwLock::new(HashMap::new())),
            fitted: true,
            name: "BaseProjector".to_string(),
        })
    }

    /// Create a new unfitted BaseProjector
    pub fn new_unfitted(n_features: usize, n_components: usize, config: ProjectorConfig) -> Self {
        Self {
            projection_matrix: Matrix::zeros((n_features, n_components)),
            mean: None,
            scale: None,
            config,
            inverse_cache: Arc::new(RwLock::new(HashMap::new())),
            fitted: false,
            name: "BaseProjector".to_string(),
        }
    }

    /// Set the projection matrix and mark as fitted
    pub fn set_projection_matrix(&mut self, matrix: Matrix) -> Result<(), MultivariousError> {
        if matrix.is_empty() {
            return Err(MultivariousError::InvalidParameter {
                name: "projection_matrix".to_string(),
                value: "empty matrix".to_string(),
                reason: "projection matrix must have at least one component".to_string(),
            });
        }

        self.projection_matrix = matrix;
        self.fitted = true;
        // Clear the cache when projection matrix changes
        self.inverse_cache.write().unwrap().clear();
        Ok(())
    }

    /// Set preprocessing parameters
    pub fn set_preprocessing(&mut self, mean: Option<Vector>, scale: Option<Vector>) -> Result<(), MultivariousError> {
        // Validate dimensions if provided
        let n_features = self.projection_matrix.nrows();

        if let Some(ref m) = mean {
            if m.len() != n_features {
                return Err(MultivariousError::DimensionMismatch {
                    expected: n_features.to_string(),
                    actual: m.len().to_string(),
                });
            }
        }

        if let Some(ref s) = scale {
            if s.len() != n_features {
                return Err(MultivariousError::DimensionMismatch {
                    expected: n_features.to_string(),
                    actual: s.len().to_string(),
                });
            }
            // Check for zero or near-zero scale values
            if s.iter().any(|&val| val.abs() < 1e-10) {
                return Err(MultivariousError::InvalidParameter {
                    name: "scale".to_string(),
                    value: "contains zero or near-zero values".to_string(),
                    reason: "scale values must be non-zero for division".to_string(),
                });
            }
        }

        self.mean = mean;
        self.scale = scale;
        Ok(())
    }

    /// Get the projection matrix
    pub fn projection_matrix(&self) -> &Matrix {
        &self.projection_matrix
    }

    /// Apply preprocessing to data
    fn preprocess(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let mut result = data.clone();

        // Center the data
        if let Some(ref mean) = self.mean {
            for mut row in result.rows_mut() {
                row -= mean;
            }
        }

        // Scale the data
        if let Some(ref scale) = self.scale {
            for mut row in result.rows_mut() {
                row /= scale;
            }
        }

        Ok(result)
    }

    /// Apply inverse preprocessing to data
    fn inverse_preprocess(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let mut result = data.clone();

        // Unscale the data
        if let Some(ref scale) = self.scale {
            for mut row in result.rows_mut() {
                row *= scale;
            }
        }

        // Uncenter the data
        if let Some(ref mean) = self.mean {
            for mut row in result.rows_mut() {
                row += mean;
            }
        }

        Ok(result)
    }

    /// Compute hash for component indices (for caching)
    fn compute_indices_hash(indices: &[usize]) -> u64 {
        use std::collections::hash_map::DefaultHasher;
        use std::hash::{Hash, Hasher};

        let mut hasher = DefaultHasher::new();
        indices.hash(&mut hasher);
        hasher.finish()
    }

    /// Compute the pseudo-inverse for a subset of components
    fn compute_partial_inverse(&self, component_indices: &[usize]) -> Result<Matrix, MultivariousError> {
        // Extract the subset of the projection matrix
        let n_features = self.projection_matrix.nrows();
        let n_selected = component_indices.len();

        if n_selected == 0 {
            return Err(MultivariousError::InvalidParameter {
                name: "component_indices".to_string(),
                value: "empty".to_string(),
                reason: "at least one component must be selected".to_string(),
            });
        }

        // Create submatrix with selected components
        let mut submatrix = Matrix::zeros((n_features, n_selected));
        for (out_idx, &comp_idx) in component_indices.iter().enumerate() {
            if comp_idx >= self.projection_matrix.ncols() {
                return Err(MultivariousError::InvalidParameter {
                    name: "component_index".to_string(),
                    value: comp_idx.to_string(),
                    reason: format!("out of bounds (max: {})", self.projection_matrix.ncols() - 1),
                });
            }
            submatrix.column_mut(out_idx).assign(&self.projection_matrix.column(comp_idx));
        }

        // Compute pseudo-inverse using SVD or other method
        // For now, we'll use the transpose for orthogonal projections
        // In a full implementation, this would use proper pseudo-inverse computation
        Ok(submatrix.t().to_owned())
    }
}

impl Project for BaseProjector {
    fn project(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        check_is_fitted(self.fitted, "BaseProjector")?;
        check_dimensions_match(
            data.ncols(),
            self.projection_matrix.nrows(),
            "data features",
            "projector features"
        )?;

        // Apply preprocessing if configured
        let processed_data = if self.config.center || self.config.scale {
            self.preprocess(data)?
        } else {
            data.clone()
        };

        // Project: X * W where W is the projection matrix
        Ok(processed_data.dot(&self.projection_matrix))
    }

    fn n_components(&self) -> usize {
        self.projection_matrix.ncols()
    }

    fn n_features(&self) -> usize {
        self.projection_matrix.nrows()
    }

    fn is_fitted(&self) -> bool {
        self.fitted
    }

    fn name(&self) -> &str {
        &self.name
    }
}

impl Reconstruct for BaseProjector {
    fn reconstruct(&self, projected: &Matrix) -> Result<Matrix, MultivariousError> {
        check_is_fitted(self.fitted, "BaseProjector")?;
        check_dimensions_match(
            projected.ncols(),
            self.projection_matrix.ncols(),
            "projected components",
            "projector components"
        )?;

        // Reconstruct: X_proj * W^T
        let reconstructed = projected.dot(&self.projection_matrix.t());

        // Apply inverse preprocessing if configured
        if self.config.center || self.config.scale {
            self.inverse_preprocess(&reconstructed)
        } else {
            Ok(reconstructed)
        }
    }
}

impl PartialProject for BaseProjector {
    fn project_components(&self, data: &Matrix, component_indices: &[usize]) -> Result<Matrix, MultivariousError> {
        check_is_fitted(self.fitted, "BaseProjector")?;
        check_dimensions_match(
            data.ncols(),
            self.projection_matrix.nrows(),
            "data features",
            "projector features"
        )?;

        if component_indices.is_empty() {
            return Ok(Matrix::zeros((data.nrows(), 0)));
        }

        // Validate component indices
        for &idx in component_indices {
            if idx >= self.projection_matrix.ncols() {
                return Err(MultivariousError::InvalidParameter {
                    name: "component_index".to_string(),
                    value: idx.to_string(),
                    reason: format!("out of bounds (max: {})", self.projection_matrix.ncols() - 1),
                });
            }
        }

        // Apply preprocessing if configured
        let processed_data = if self.config.center || self.config.scale {
            self.preprocess(data)?
        } else {
            data.clone()
        };

        // Create result matrix
        let n_samples = data.nrows();
        let n_selected = component_indices.len();
        let mut result = Matrix::zeros((n_samples, n_selected));

        // Project onto selected components
        for (out_idx, &comp_idx) in component_indices.iter().enumerate() {
            let component = self.projection_matrix.column(comp_idx);
            let projected_values = processed_data.dot(&component);
            result.column_mut(out_idx).assign(&projected_values);
        }

        Ok(result)
    }

    fn component_importance(&self) -> Result<Vector, MultivariousError> {
        check_is_fitted(self.fitted, "BaseProjector")?;

        // For base projector, assume all components have equal importance
        // Derived classes can override this with actual importance scores
        Ok(Vector::ones(self.n_components()))
    }
}

/// Builder for BaseProjector
#[derive(Debug, Clone)]
pub struct BaseProjectorBuilder {
    projection_matrix: Option<Matrix>,
    mean: Option<Vector>,
    scale: Option<Vector>,
    config: ProjectorConfig,
    name: String,
}

impl BaseProjectorBuilder {
    pub fn new() -> Self {
        Self {
            projection_matrix: None,
            mean: None,
            scale: None,
            config: ProjectorConfig::default(),
            name: "BaseProjector".to_string(),
        }
    }

    pub fn projection_matrix(mut self, matrix: Matrix) -> Self {
        self.projection_matrix = Some(matrix);
        self
    }

    pub fn mean(mut self, mean: Vector) -> Self {
        self.mean = Some(mean);
        self
    }

    pub fn scale(mut self, scale: Vector) -> Self {
        self.scale = Some(scale);
        self
    }

    pub fn config(mut self, config: ProjectorConfig) -> Self {
        self.config = config;
        self
    }

    pub fn name(mut self, name: String) -> Self {
        self.name = name;
        self
    }

    pub fn build(self) -> Result<BaseProjector, MultivariousError> {
        let projection_matrix = self.projection_matrix
            .ok_or_else(|| MultivariousError::InvalidParameter {
                name: "projection_matrix".to_string(),
                value: "None".to_string(),
                reason: "projection matrix is required".to_string(),
            })?;

        let mut projector = BaseProjector::new(projection_matrix, self.config)?;
        projector.set_preprocessing(self.mean, self.scale)?;
        projector.name = self.name;
        Ok(projector)
    }
}

impl Default for BaseProjectorBuilder {
    fn default() -> Self {
        Self::new()
    }
}

