        // Project onto components 0 and 2
        let projected = projector.project_components(&data, &[0, 2]).unwrap();
        assert_eq!(projected.shape(), &[2, 2]);
        assert_eq!(projected[[0, 0]], 1.0);
        assert_eq!(projected[[0, 1]], 5.0); // 0.5 * (1 + 2 + 3 + 4)
