        let scale = array![2.0, 4.0];

        let mut config = ProjectorConfig::default();
        config.center = true;
        config.scale = true;

        let mut projector = BaseProjector::new(projection_matrix, config).unwrap();
        projector.set_preprocessing(Some(mean), Some(scale)).unwrap();

        let data = array![
            [3.0, 10.0],
            [5.0, 6.0],
        ];

        let projected = projector.project(&data).unwrap();
        // After centering: [[2, 8], [4, 4]]
        // After scaling: [[1, 2], [2, 1]]
        // After projection: [[1, 2], [2, 1]]
        assert_eq!(projected[[0, 0]], 1.0);
        assert_eq!(projected[[0, 1]], 2.0);
        assert_eq!(projected[[1, 0]], 2.0);
        assert_eq!(projected[[1, 1]], 1.0);
