    #[test]
    fn test_builder() {
        let projection_matrix = array![
            [1.0, 0.0],
            [0.0, 1.0],
        ];

        let projector = BaseProjectorBuilder::new()
            .projection_matrix(projection_matrix)
            .name("TestProjector".to_string())
            .build()
            .unwrap();

        assert_eq!(projector.name(), "TestProjector");
        assert_eq!(projector.n_components(), 2);
    }

    #[test]
    fn test_error_handling() {
        // Empty projection matrix
        let empty_matrix = Matrix::zeros((0, 0));
        let result = BaseProjector::new(empty_matrix, ProjectorConfig::default());
        assert!(result.is_err());

        // Dimension mismatch
        let projection_matrix = array![
            [1.0, 0.0],
            [0.0, 1.0],
        ];
        let projector = BaseProjector::new(projection_matrix, ProjectorConfig::default()).unwrap();

        let wrong_data = array![
            [1.0, 2.0, 3.0], // 3 features instead of 2
        ];
        let result = projector.project(&wrong_data);
        assert!(result.is_err());

        // Invalid component index
        let data = array![
            [1.0, 2.0],
        ];
        let result = projector.project_components(&data, &[5]); // Index out of bounds
        assert!(result.is_err());
    }
}

