//! Truncated SVD implementation
//!
//! This module provides truncated SVD for computing only the
//! k largest singular values and their corresponding vectors.

use crate::common_types::{Matrix, Vector};
use crate::errors::MultivariousError;
use crate::svd::{SvdMethod, SvdResult, SvdSolver};
use crate::validation::{validate_finite, validate_matrix_not_empty};

/// Truncated SVD solver for computing only k components
pub struct TruncatedSvd {
    /// Number of components to compute
    n_components: usize,
    /// Tolerance for convergence
    tolerance: f64,
    /// Maximum iterations
    max_iter: usize,
}

impl TruncatedSvd {
    /// Create a new truncated SVD solver
    pub fn new(n_components: usize) -> Self {
        Self {
            n_components,
            tolerance: 1e-10,
            max_iter: 1000,
        }
    }

    /// Set the convergence tolerance
    pub fn with_tolerance(mut self, tolerance: f64) -> Self {
        self.tolerance = tolerance;
        self
    }

    /// Set the maximum number of iterations
    pub fn with_max_iter(mut self, max_iter: usize) -> Self {
        self.max_iter = max_iter;
        self
    }

    /// Validate that n_components is valid for the given matrix
    fn validate_components(&self, matrix: &Matrix) -> Result<(), MultivariousError> {
        let max_components = matrix.nrows().min(matrix.ncols());
        if self.n_components == 0 {
            return Err(MultivariousError::InvalidParameter {
                name: "n_components".to_string(),
                value: "0".to_string(),
                reason: "must be at least 1".to_string(),
            });
        }
        if self.n_components > max_components {
            return Err(MultivariousError::InvalidParameter {
                name: "n_components".to_string(),
                value: self.n_components.to_string(),
                reason: format!("cannot exceed min(rows, cols) = {}", max_components),
            });
        }
        Ok(())
    }
}

