    #[test]
    fn test_randomized_svd_creation() {
        let svd = RandomizedSvd::new(10);
        assert_eq!(svd.n_components, 10);
        assert_eq!(svd.n_iter, 4);
        assert_eq!(svd.seed, None);
        assert_eq!(svd.oversampling, 10);
    }

    #[test]
    fn test_randomized_svd_builder() {
        let svd = RandomizedSvd::new(5)
            .with_n_iter(2)
            .with_seed(42)
            .with_oversampling(5);
        assert_eq!(svd.n_components, 5);
        assert_eq!(svd.n_iter, 2);
        assert_eq!(svd.seed, Some(42));
        assert_eq!(svd.oversampling, 5);
    }

    #[test]
    fn test_validate_parameters() {
        let matrix = test_matrix(20, 15); // max components = 15

        // Valid parameters
        let svd_valid = RandomizedSvd::new(5).with_oversampling(5);
        assert!(svd_valid.validate_parameters(&matrix).is_ok());

        // Too many components
        let svd_too_many = RandomizedSvd::new(20);
        assert!(svd_too_many.validate_parameters(&matrix).is_err());

        // Zero components
        let svd_zero = RandomizedSvd::new(0);
        assert!(svd_zero.validate_parameters(&matrix).is_err());

        // Oversampling exceeds matrix size
        let svd_oversample = RandomizedSvd::new(10).with_oversampling(10);
        assert!(svd_oversample.validate_parameters(&matrix).is_err());
    }

    #[test]
    fn test_method_validation() {
        let svd = RandomizedSvd::new(5).with_n_iter(3).with_seed(42).with_oversampling(4);
        let matrix = test_matrix(10, 10);

        // Should accept matching randomized method
        let result = svd.compute(&matrix, SvdMethod::Randomized {
            n_components: 5,
            n_iter: 3,
            seed: Some(42),
        });
        assert!(result.is_err()); // Still fails due to placeholder

        // Should reject non-randomized methods
        let result = svd.compute(&matrix, SvdMethod::Full);
        assert!(matches!(
            result,
            Err(MultivariousError::InvalidParameter { ref name, .. }) if name == "method"
        ));

        // Should reject mismatched parameters
        let result = svd.compute(&matrix, SvdMethod::Randomized {
            n_components: 3,
            n_iter: 3,
            seed: Some(42),
        });
        assert!(matches!(
            result,
            Err(MultivariousError::InvalidParameter { name, .. }) if name == "method.n_components"
        ));
    }

    #[test]
    fn test_placeholder_errors() {
        let svd = RandomizedSvd::new(5);
        let matrix = test_matrix(20, 15);

        let method = SvdMethod::Randomized {
            n_components: 5,
            n_iter: 4,
            seed: None,
        };
        assert!(svd.compute(&matrix, method).is_err());
        assert!(svd.singular_values(&matrix).is_err());
        assert!(svd.matrix_rank(&matrix, None).is_err());
    }

    #[test]
    fn test_range_finder_validation() {
        let matrix = test_matrix(10, 8);

        // Invalid size
        assert!(randomized_range_finder(&matrix, 0, 2, None).is_err());
        assert!(randomized_range_finder(&matrix, 10, 2, None).is_err());

        // Valid size (still returns placeholder error)
        assert!(randomized_range_finder(&matrix, 5, 2, None).is_err());
    }

    #[test]
    fn test_subspace_iteration_validation() {
        let matrix = test_matrix(10, 8);
        let q_valid = test_matrix(8, 5);
        let q_invalid = test_matrix(10, 5);

        // Dimension mismatch
        assert!(subspace_iteration(&matrix, &q_invalid, 2).is_err());

        // Valid dimensions (still returns placeholder error)
        assert!(subspace_iteration(&matrix, &q_valid, 2).is_err());
    }
}

