//! Randomized SVD implementation
//!
//! This module provides randomized SVD algorithms for efficient
//! computation of low-rank approximations of large matrices.
//! Based on Halko, Martinsson, and Tropp (2011).

use crate::common_types::{Matrix, Vector};
use crate::errors::MultivariousError;
