use crate::errors::MultivariousError;
use crate::common_types::Matrix;
use serde::{Serialize, Deserialize};

/// Core trait for preprocessing operations on data matrices
pub trait Preprocessor: Send + Sync + std::fmt::Debug {
    /// Fit the preprocessor to training data
    fn fit(&mut self, data: &Matrix) -> Result<(), MultivariousError>;

    /// Transform data using fitted parameters
    fn transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError>;

    /// Inverse transform data back to original space
    fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError>;

    /// Fit and transform in one step
    fn fit_transform(&mut self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        self.fit(data)?;
        self.transform(data)
    }

    /// Check if the preprocessor has been fitted
    fn is_fitted(&self) -> bool;

    /// Get the name of the preprocessor
    fn name(&self) -> &str;
}

/// Builder pattern for creating preprocessing pipelines
pub trait PreprocessorBuilder {
    /// Build the preprocessor
    fn build(self) -> Result<Box<dyn Preprocessor>, MultivariousError>;
}

/// Configuration for preprocessing steps
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PreprocessConfig {
    /// Whether to apply preprocessing column-wise (true) or row-wise (false)
    pub by_column: bool,
    /// Whether to skip NA values
    pub skip_na: bool,
    /// Minimum standard deviation to avoid division by zero
    pub min_std: f64,
}

impl Default for PreprocessConfig {
    fn default() -> Self {
        Self {
            by_column: true,
            skip_na: true,

