use crate::errors::MultivariousError;
use crate::common_types::{Matrix, Vector};
use crate::preprocessing::traits::{Preprocessor, PreprocessConfig};
use ndarray::Axis;
use serde::{Serialize, Deserialize};

/// Center data by subtracting mean
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Center {
    means: Option<Vector>,
    config: PreprocessConfig,
}

impl Center {
    pub fn new() -> Self {
        Self {
            means: None,
            config: PreprocessConfig::default(),
        }
    }

    pub fn with_config(config: PreprocessConfig) -> Self {
        Self {
            means: None,
            config,
        }
    }
}

impl Default for Center {
    fn default() -> Self {
        Self::new()
    }
}

impl Preprocessor for Center {
    fn fit(&mut self, data: &Matrix) -> Result<(), MultivariousError> {
        let axis = if self.config.by_column { Axis(0) } else { Axis(1) };
        let means = data.mean_axis(axis).ok_or_else(|| {
            MultivariousError::PreprocessingError("Failed to compute means".to_string())
        })?;
        self.means = Some(means);
        Ok(())
    }

    fn transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let means = self.means.as_ref().ok_or_else(|| {
            MultivariousError::PreprocessingError("Center not fitted".to_string())
        })?;

        if self.config.by_column {
            if data.ncols() != means.len() {
                return Err(MultivariousError::DimensionMismatch {
                    expected: means.len().to_string(),
                    actual: data.ncols().to_string(),
                });
            }
            Ok(data - &means.view().insert_axis(Axis(0)))
        } else {
            if data.nrows() != means.len() {
                return Err(MultivariousError::DimensionMismatch {
                    expected: means.len().to_string(),
                    actual: data.nrows().to_string(),
                });
            }
            Ok(data - &means.view().insert_axis(Axis(1)))
        }
    }

    fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let means = self.means.as_ref().ok_or_else(|| {
            MultivariousError::PreprocessingError("Center not fitted".to_string())
        })?;

        if self.config.by_column {
            Ok(data + &means.view().insert_axis(Axis(0)))
        } else {
            Ok(data + &means.view().insert_axis(Axis(1)))
        }
    }

    fn is_fitted(&self) -> bool {
        self.means.is_some()
    }

    fn name(&self) -> &str {
        "Center"
    }

    fn clone_box(&self) -> Box<dyn Preprocessor> {
        Box::new(self.clone())
    }
}

/// Scale data to unit variance
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Scale {
    stds: Option<Vector>,
    config: PreprocessConfig,
}

impl Scale {
    pub fn new() -> Self {
        Self {
            stds: None,
            config: PreprocessConfig::default(),
        }
    }

    pub fn with_config(config: PreprocessConfig) -> Self {
        Self {
            stds: None,
            config,
        }
    }
}

impl Default for Scale {
    fn default() -> Self {
        Self::new()
    }
}

impl Preprocessor for Scale {
    fn fit(&mut self, data: &Matrix) -> Result<(), MultivariousError> {
        let axis = if self.config.by_column { Axis(0) } else { Axis(1) };
        let stds = data.std_axis(axis, 1.0);

        // Replace zero or near-zero standard deviations with min_std
        let stds = stds.mapv(|s| if s < self.config.min_std { self.config.min_std } else { s });

        self.stds = Some(stds);
        Ok(())
    }

    fn transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let stds = self.stds.as_ref().ok_or_else(|| {
            MultivariousError::PreprocessingError("Scale not fitted".to_string())
        })?;

        if self.config.by_column {
            if data.ncols() != stds.len() {
                return Err(MultivariousError::DimensionMismatch {
                    expected: stds.len().to_string(),
                    actual: data.ncols().to_string(),
                });
            }
            Ok(data / &stds.view().insert_axis(Axis(0)))
        } else {
            if data.nrows() != stds.len() {
                return Err(MultivariousError::DimensionMismatch {
                    expected: stds.len().to_string(),
                    actual: data.nrows().to_string(),
                });
            }
            Ok(data / &stds.view().insert_axis(Axis(1)))
        }
    }

    fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let stds = self.stds.as_ref().ok_or_else(|| {
            MultivariousError::PreprocessingError("Scale not fitted".to_string())
        })?;

        if self.config.by_column {
            Ok(data * &stds.view().insert_axis(Axis(0)))
        } else {
            Ok(data * &stds.view().insert_axis(Axis(1)))
        }
    }

    fn is_fitted(&self) -> bool {
        self.stds.is_some()
    }

    fn name(&self) -> &str {
        "Scale"
    }

    fn clone_box(&self) -> Box<dyn Preprocessor> {
        Box::new(self.clone())
    }
}

/// Standardize data (center and scale)
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Standardize {
    means: Option<Vector>,
    stds: Option<Vector>,
    config: PreprocessConfig,
}

impl Standardize {
    pub fn new() -> Self {
        Self {
            means: None,
            stds: None,
            config: PreprocessConfig::default(),
        }
    }

    pub fn with_config(config: PreprocessConfig) -> Self {
        Self {
            means: None,
            stds: None,
            config,
        }
    }
}

impl Default for Standardize {
    fn default() -> Self {
        Self::new()
    }
}

impl Preprocessor for Standardize {
    fn fit(&mut self, data: &Matrix) -> Result<(), MultivariousError> {
        let axis = if self.config.by_column { Axis(0) } else { Axis(1) };

        let means = data.mean_axis(axis).ok_or_else(|| {
            MultivariousError::PreprocessingError("Failed to compute means".to_string())
        })?;

        let stds = data.std_axis(axis, 1.0);
        let stds = stds.mapv(|s| if s < self.config.min_std { self.config.min_std } else { s });

        self.means = Some(means);
        self.stds = Some(stds);
        Ok(())
    }

    fn transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let means = self.means.as_ref().ok_or_else(|| {
            MultivariousError::PreprocessingError("Standardize not fitted".to_string())
        })?;
        let stds = self.stds.as_ref().ok_or_else(|| {
            MultivariousError::PreprocessingError("Standardize not fitted".to_string())
        })?;

        if self.config.by_column {
            if data.ncols() != means.len() || data.ncols() != stds.len() {
                return Err(MultivariousError::DimensionMismatch {
                    expected: means.len().to_string(),
                    actual: data.ncols().to_string(),
                });
            }
            let centered = data - &means.view().insert_axis(Axis(0));
            Ok(&centered / &stds.view().insert_axis(Axis(0)))
        } else {
            if data.nrows() != means.len() || data.nrows() != stds.len() {
                return Err(MultivariousError::DimensionMismatch {
                    expected: means.len().to_string(),
                    actual: data.nrows().to_string(),
                });
            }
            let centered = data - &means.view().insert_axis(Axis(1));
            Ok(&centered / &stds.view().insert_axis(Axis(1)))
        }
    }

    fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let means = self.means.as_ref().ok_or_else(|| {
            MultivariousError::PreprocessingError("Standardize not fitted".to_string())
        })?;
        let stds = self.stds.as_ref().ok_or_else(|| {
            MultivariousError::PreprocessingError("Standardize not fitted".to_string())
        })?;

        if self.config.by_column {
            let scaled = data * &stds.view().insert_axis(Axis(0));
            Ok(&scaled + &means.view().insert_axis(Axis(0)))
        } else {
            let scaled = data * &stds.view().insert_axis(Axis(1));
            Ok(&scaled + &means.view().insert_axis(Axis(1)))
        }
    }

    fn is_fitted(&self) -> bool {
        self.means.is_some() && self.stds.is_some()
    }

    fn name(&self) -> &str {
        "Standardize"
    }

    fn clone_box(&self) -> Box<dyn Preprocessor> {
        Box::new(self.clone())
    }
}

/// Pass-through preprocessor (no-op)
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Pass;

impl Pass {
    pub fn new() -> Self {
        Self
    }
}

impl Default for Pass {
    fn default() -> Self {
        Self::new()
    }
}

impl Preprocessor for Pass {
    fn fit(&mut self, _data: &Matrix) -> Result<(), MultivariousError> {
        Ok(())
    }

    fn transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        Ok(data.clone())
    }

    fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        Ok(data.clone())
    }

    fn is_fitted(&self) -> bool {
        true
    }

    fn name(&self) -> &str {
        "Pass"
    }

    fn clone_box(&self) -> Box<dyn Preprocessor> {
        Box::new(self.clone())
    }
}

/// Pipeline of preprocessing steps
#[derive(Debug)]
pub struct Pipeline {
    steps: Vec<Box<dyn Preprocessor>>,
}

impl Pipeline {
    pub fn new() -> Self {
        Self { steps: Vec::new() }
    }

    pub fn add(mut self, step: Box<dyn Preprocessor>) -> Self {
        self.steps.push(step);
        self
    }

    pub fn len(&self) -> usize {
        self.steps.len()
    }

    pub fn is_empty(&self) -> bool {
        self.steps.is_empty()
    }
}

impl Default for Pipeline {
    fn default() -> Self {
        Self::new()
    }
}

impl Preprocessor for Pipeline {
    fn fit(&mut self, data: &Matrix) -> Result<(), MultivariousError> {
        let mut current = data.clone();

        for step in &mut self.steps {
            step.fit(&current)?;
            current = step.transform(&current)?;
        }

        Ok(())
    }

    fn transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let mut current = data.clone();

        for step in &self.steps {
            current = step.transform(&current)?;
        }

        Ok(current)
    }

    fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let mut current = data.clone();

        // Apply inverse transforms in reverse order
        for step in self.steps.iter().rev() {
            current = step.inverse_transform(&current)?;
        }

        Ok(current)
    }

    fn is_fitted(&self) -> bool {
        self.steps.iter().all(|s| s.is_fitted())
    }

    fn name(&self) -> &str {
        "Pipeline"
    }

    fn clone_box(&self) -> Box<dyn Preprocessor> {
        Box::new(self.clone())
    }
}

