//! Randomized SVD implementation
//!
//! This module provides randomized SVD algorithms for efficient
//! computation of low-rank approximations of large matrices.
//! Based on Halko, Martinsson, and Tropp (2011).

use crate::common_types::{Matrix, Vector};
use crate::errors::MultivariousError;
use crate::svd::{SvdMethod, SvdResult, SvdSolver};
use crate::validation::{validate_finite, validate_matrix_not_empty};

/// Randomized SVD solver for large matrices
pub struct RandomizedSvd {
    /// Number of components to compute
    n_components: usize,
    /// Number of power iterations for improved accuracy
    n_iter: usize,
    /// Random seed for reproducibility
    seed: Option<u64>,
    /// Oversampling parameter (typically 5-10)
    oversampling: usize,
}

impl RandomizedSvd {
    /// Create a new randomized SVD solver
    pub fn new(n_components: usize) -> Self {
        Self {
            n_components,
            n_iter: 4,
            seed: None,
            oversampling: 10,
        }
    }

    /// Set the number of power iterations
    pub fn with_n_iter(mut self, n_iter: usize) -> Self {
        self.n_iter = n_iter;
        self
    }

    /// Set the random seed for reproducibility
    pub fn with_seed(mut self, seed: u64) -> Self {
        self.seed = Some(seed);
        self
    }

    /// Set the oversampling parameter
    pub fn with_oversampling(mut self, oversampling: usize) -> Self {
        self.oversampling = oversampling;
        self
    }

    /// Validate parameters for the given matrix
    fn validate_parameters(&self, matrix: &Matrix) -> Result<(), MultivariousError> {
        let max_components = matrix.nrows().min(matrix.ncols());

        if self.n_components == 0 {
            return Err(MultivariousError::InvalidParameter {
                name: "n_components".to_string(),
                value: "0".to_string(),
                reason: "must be at least 1".to_string(),
            });
        }

        if self.n_components > max_components {
            return Err(MultivariousError::InvalidParameter {
                name: "n_components".to_string(),
                value: self.n_components.to_string(),
                reason: format!("cannot exceed min(rows, cols) = {}", max_components),
            });
        }

        if self.n_components + self.oversampling > matrix.ncols() {
            return Err(MultivariousError::InvalidParameter {
                name: "n_components + oversampling".to_string(),
                value: (self.n_components + self.oversampling).to_string(),
                reason: format!("cannot exceed number of columns = {}", matrix.ncols()),
            });
        }

        Ok(())
    }

